    /**
     * @method
     * @name dydx#fetchTime
     * @description fetches the current integer timestamp in milliseconds from the exchange server
     * @see https://docs.dydx.xyz/indexer-client/http#get-time
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int} the current integer timestamp in milliseconds from the exchange server
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTime(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.indexerGetTime(parameters)).join();
            //
            // {
            //     "iso": "2025-07-20T15:12:13.466Z",
            //     "epoch": 1753024333.466
            // }
            //
            return this.safeInteger(response, "epoch");
        });

    }

    public Object parseMarket(Object market)
    {
        //
        // {
        //     "clobPairId": "0",
        //     "ticker": "BTC-USD",
        //     "status": "ACTIVE",
        //     "oraclePrice": "118976.5376",
        //     "priceChange24H": "659.9736",
        //     "volume24H": "1292729.3605",
        //     "trades24H": 9387,
        //     "nextFundingRate": "0",
        //     "initialMarginFraction": "0.02",
        //     "maintenanceMarginFraction": "0.012",
        //     "openInterest": "52.0691",
        //     "atomicResolution": -10,
        //     "quantumConversionExponent": -9,
        //     "tickSize": "1",
        //     "stepSize": "0.0001",
        //     "stepBaseQuantums": 1000000,
        //     "subticksPerTick": 100000,
        //     "marketType": "CROSS",
        //     "openInterestLowerCap": "0",
        //     "openInterestUpperCap": "0",
        //     "baseOpenInterest": "50.3776",
        //     "defaultFundingRate1H": "0"
        // }
        //
        Object quoteId = "USDC";
        Object marketId = this.safeString(market, "ticker");
        Object parts = Helpers.split(marketId, "-");
        Object baseName = this.safeString(parts, 0);
        Object baseId = this.safeString(market, "baseId", baseName); // idk where 'baseId' comes from, but leaving as is
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object settleId = "USDC";
        Object settle = this.safeCurrencyCode(settleId);
        Object symbol = Helpers.add(Helpers.add(Helpers.add(Helpers.add(base, "/"), quote), ":"), settle);
        Object contract = true;
        Object swap = true;
        Object amountPrecisionStr = this.safeString(market, "stepSize");
        Object pricePrecisionStr = this.safeString(market, "tickSize");
        Object status = this.safeString(market, "status");
        Object active = true;
        if (Helpers.isTrue(!Helpers.isEqual(status, "ACTIVE")))
        {
            active = false;
        }
        final Object finalBase = base;
        final Object finalActive = active;
        return this.safeMarketStructure(new java.util.HashMap<String, Object>() {{
            put( "id", DydxCore.this.safeString(market, "ticker") );
            put( "symbol", symbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", settle );
            put( "baseId", baseId );
            put( "baseName", baseName );
            put( "quoteId", quoteId );
            put( "settleId", settleId );
            put( "type", "swap" );
            put( "spot", false );
            put( "margin", null );
            put( "swap", swap );
            put( "future", false );
            put( "option", false );
            put( "active", finalActive );
            put( "contract", contract );
            put( "contractSize", DydxCore.this.parseNumber("1") );
            put( "linear", true );
            put( "inverse", false );
            put( "taker", null );
            put( "maker", null );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", DydxCore.this.parseNumber(amountPrecisionStr) );
                put( "price", DydxCore.this.parseNumber(pricePrecisionStr) );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
            }} );
            put( "created", null );
            put( "info", market );
        }});
    }

