    public Object hashMessage(Object message)
    {
        return this.hash(message, keccak(), "hex");
    }

    public Object signHash(Object hash, Object privateKey)
    {
        Object signature = ecdsa(Helpers.slice(hash, Helpers.opNeg(64), null), Helpers.slice(privateKey, Helpers.opNeg(64), null), secp256k1(), null);
        Object r = Helpers.GetValue(signature, "r");
        Object s = Helpers.GetValue(signature, "s");
        return new java.util.HashMap<String, Object>() {{
            put( "r", Helpers.padStart((String)r, ((Number)64).intValue(), ((String)"0").charAt(0)) );
            put( "s", Helpers.padStart((String)s, ((Number)64).intValue(), ((String)"0").charAt(0)) );
            put( "v", DydxCore.this.sum(27, Helpers.GetValue(signature, "v")) );
        }};
    }

    public Object signMessage(Object message, Object privateKey)
    {
        return this.signHash(this.hashMessage(message), Helpers.slice(privateKey, Helpers.opNeg(64), null));
    }

    public Object signOnboardingAction()
    {
        Object message = new java.util.HashMap<String, Object>() {{
            put( "action", "dYdX Chain Onboarding" );
        }};
        Object chainId = Helpers.GetValue(this.options, "chainId");
        Object domain = new java.util.HashMap<String, Object>() {{
            put( "chainId", chainId );
            put( "name", "dYdX Chain" );
        }};
        Object messageTypes = new java.util.HashMap<String, Object>() {{
            put( "dYdX", new java.util.ArrayList<Object>(java.util.Arrays.asList(new java.util.HashMap<String, Object>() {{
    put( "name", "action" );
    put( "type", "string" );
}})) );
        }};
        Object msg = this.ethEncodeStructuredData(domain, messageTypes, message);
        if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(this.privateKey, null)) || Helpers.isTrue(Helpers.isEqual(this.privateKey, ""))))
        {
            throw new ArgumentsRequired((String)Helpers.add(this.id, " signOnboardingAction() requires a privateKey to be set.")) ;
        }
        Object signature = this.signMessage(msg, this.privateKey);
        return signature;
    }

    public Object signDydxTx(Object privateKey, Object message, Object memo, Object chainId, Object account, Object authenticators, Object... optionalArgs)
    {
        Object fee = Helpers.getArg(optionalArgs, 0, null);
        var encodedTxsignDocVariable = this.encodeDydxTxForSigning(message, memo, chainId, account, authenticators, fee);
        var encodedTx = ((java.util.List<Object>) encodedTxsignDocVariable).get(0);
        var signDoc = ((java.util.List<Object>) encodedTxsignDocVariable).get(1);
        Object signature = this.signHash(encodedTx, privateKey);
        return this.encodeDydxTxRaw(signDoc, Helpers.add(Helpers.GetValue(signature, "r"), Helpers.GetValue(signature, "s")));
    }

    public Object retrieveCredentials()
    {
        Object credentials = this.safeDict(this.options, "dydxCredentials");
        if (Helpers.isTrue(!Helpers.isEqual(credentials, null)))
        {
            return credentials;
        }
        Object entropy = this.safeString(this.options, "mnemonic");
        if (Helpers.isTrue(Helpers.isEqual(entropy, null)))
        {
            Object signature = this.signOnboardingAction();
            entropy = this.hashMessage(this.base16ToBinary(Helpers.add(Helpers.GetValue(signature, "r"), Helpers.GetValue(signature, "s"))));
        }
        credentials = this.retrieveDydxCredentials(entropy);
        Helpers.addElementToObject(credentials, "privateKey", this.binaryToBase16(Helpers.GetValue(credentials, "privateKey")));
        Helpers.addElementToObject(credentials, "publicKey", this.binaryToBase16(Helpers.GetValue(credentials, "publicKey")));
        Helpers.addElementToObject(this.options, "dydxCredentials", credentials);
        return credentials;
    }

    public java.util.concurrent.CompletableFuture<Object> fetchDydxAccount()
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            // required in js
            (this.loadDydxProtos()).join();
            Object dydxAccount = this.safeDict(this.options, "dydxAccount");
            if (Helpers.isTrue(!Helpers.isEqual(dydxAccount, null)))
            {
                return dydxAccount;
            }
            if (Helpers.isTrue(Helpers.isEqual(this.walletAddress, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchDydxAccount() requires the walletAddress to be set using the dydx chain address eg: dydx1cpb4tedmwq304c2kc9pwzjwq0sc6z2a4tasxrz")) ;
            }
            if (!Helpers.isTrue(((String)this.walletAddress).startsWith(((String)"dydx"))))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " fetchDydxAccount() requires a valid dydx chain address, starting with dydx, not the l1 address.")) ;
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "dydxAddress", DydxCore.this.walletAddress );
            }};
            //
            // {
            //     "info": {
            //         "address": "string",
            //         "pub_key": {
            //             "type_url": "string",
            //             "key": "string"
            //         },
            //         "account_number": "string",
            //         "sequence": "string"
            //     }
            // }
            //
            Object response = (this.nodeRestGetCosmosAuthV1beta1AccountInfoDydxAddress(request)).join();
            Object account = this.safeDict(response, "info", new java.util.HashMap<String, Object>() {{}});
            Helpers.addElementToObject(account, "pub_key", new java.util.HashMap<String, Object>() {{
        put( "key", Helpers.GetValue(Helpers.GetValue(account, "pub_key"), "key") );
    }});
            Helpers.addElementToObject(this.options, "dydxAccount", account);
            return account;
        });

    }

    public Object pow(Object n, Object m)
    {
        Object r = Precise.stringMul(n, "1");
        Object c = this.parseToInt(m);
        // TODO: cap
        for (var i = 1; Helpers.isLessThan(i, c); i++)
        {
            r = Precise.stringMul(r, n);
        }
        return r;
    }

    public Object createOrderRequest(Object symbol, Object type, Object side, Object amount, Object... optionalArgs)
    {
        Object price = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object reduceOnly = this.safeBool2(parameters, "reduceOnly", "reduce_only", false);
        Object orderType = ((String)type).toUpperCase();
        Object market = this.market(symbol);
        Object orderSide = ((String)side).toUpperCase();
        Object subaccountId = 0;
        var subaccountIdparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "subAccountId", subaccountId);
        subaccountId = ((java.util.List<Object>) subaccountIdparametersVariable).get(0);
        parameters = ((java.util.List<Object>) subaccountIdparametersVariable).get(1);
        Object triggerPrice = this.safeString2(parameters, "triggerPrice", "stopPrice");
        Object stopLossPrice = this.safeValue(parameters, "stopLossPrice", triggerPrice);
        Object takeProfitPrice = this.safeValue(parameters, "takeProfitPrice");
        Object isConditional = Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(triggerPrice, null)) || Helpers.isTrue(!Helpers.isEqual(stopLossPrice, null))) || Helpers.isTrue(!Helpers.isEqual(takeProfitPrice, null));
        Object isMarket = Helpers.isEqual(orderType, "MARKET");
        Object timeInForce = this.safeStringUpper(parameters, "timeInForce", "GTT");
        Object postOnly = this.isPostOnly(isMarket, null, parameters);
        Object amountStr = this.amountToPrecision(symbol, amount);
        Object priceStr = this.priceToPrecision(symbol, price);
        Object marketInfo = this.safeDict(market, "info", new java.util.HashMap<String, Object>() {{}});
        Object atomicResolution = Helpers.GetValue(marketInfo, "atomicResolution");
        Object quantumScale = this.pow("10", Precise.stringNeg(atomicResolution));
        Object quantums = Precise.stringMul(amountStr, quantumScale);
        Object quantumConversionExponent = Helpers.GetValue(marketInfo, "quantumConversionExponent");
        Object priceScale = this.pow("10", Precise.stringSub(Precise.stringSub(atomicResolution, quantumConversionExponent), "-6"));
        Object subticks = Precise.stringMul(priceStr, priceScale);
        Object clientMetadata = 0;
        Object conditionalType = 0;
        Object conditionalOrderTriggerSubticks = "0";
        Object orderFlag = null;
        Object timeInForceNumber = null;
        if (Helpers.isTrue(Helpers.isEqual(timeInForce, "FOK")))
        {
            throw new InvalidOrder((String)Helpers.add(this.id, " timeInForce fok has been deprecated")) ;
        }
        if (Helpers.isTrue(Helpers.isEqual(orderType, "MARKET")))
        {
            // short-term
            orderFlag = 0;
            clientMetadata = 1; // STOP_MARKET / TAKE_PROFIT_MARKET
            if (Helpers.isTrue(!Helpers.isEqual(timeInForce, null)))
            {
                // default is ioc
                timeInForceNumber = 1;
            }
        } else if (Helpers.isTrue(Helpers.isEqual(orderType, "LIMIT")))
        {
            if (Helpers.isTrue(Helpers.isEqual(timeInForce, "GTT")))
            {
                // long-term
                orderFlag = 64;
                if (Helpers.isTrue(postOnly))
                {
                    timeInForceNumber = 2;
                } else
                {
                    timeInForceNumber = 0;
                }
            } else
            {
                orderFlag = 0;
                if (Helpers.isTrue(Helpers.isEqual(timeInForce, "IOC")))
                {
                    timeInForceNumber = 1;
                } else
                {
                    throw new InvalidOrder((String)"unexpected code path: timeInForce") ;
                }
            }
        }
        if (Helpers.isTrue(isConditional))
        {
            // conditional
            orderFlag = 32;
            if (Helpers.isTrue(!Helpers.isEqual(stopLossPrice, null)))
            {
                conditionalType = 1;
                conditionalOrderTriggerSubticks = this.priceToPrecision(symbol, stopLossPrice);
            } else if (Helpers.isTrue(!Helpers.isEqual(takeProfitPrice, null)))
            {
                conditionalType = 2;
                conditionalOrderTriggerSubticks = this.priceToPrecision(symbol, takeProfitPrice);
            }
            conditionalOrderTriggerSubticks = Precise.stringMul(conditionalOrderTriggerSubticks, priceScale);
        }
        Object latestBlockHeight = this.safeInteger(parameters, "latestBlockHeight");
        Object goodTillBlock = this.safeInteger(parameters, "goodTillBlock");
        Object goodTillBlockTime = null;
        Object goodTillBlockTimeInSeconds = 2592000;
        var goodTillBlockTimeInSecondsparametersVariable = this.handleOptionAndParams(parameters, "createOrder", "goodTillBlockTimeInSeconds", goodTillBlockTimeInSeconds);
        goodTillBlockTimeInSeconds = ((java.util.List<Object>) goodTillBlockTimeInSecondsparametersVariable).get(0);
        parameters = ((java.util.List<Object>) goodTillBlockTimeInSecondsparametersVariable).get(1); // default is 30 days
        if (Helpers.isTrue(Helpers.isEqual(orderFlag, 0)))
        {
            if (Helpers.isTrue(Helpers.isEqual(goodTillBlock, null)))
            {
                // short term order
                goodTillBlock = Helpers.add(latestBlockHeight, 20);
            }
        } else
        {
            if (Helpers.isTrue(Helpers.isEqual(goodTillBlockTimeInSeconds, null)))
            {
                throw new ArgumentsRequired((String)"goodTillBlockTimeInSeconds is required.") ;
            }
            goodTillBlockTime = Helpers.add(this.seconds(), goodTillBlockTimeInSeconds);
        }
        Object sideNumber = ((Helpers.isTrue((Helpers.isEqual(orderSide, "BUY"))))) ? 1 : 2;
        Object defaultClientOrderId = this.randNumber(9); // 2**32 - 1 is 10 digits, but it may overflow with 10
        Object clientOrderId = this.safeInteger(parameters, "clientOrderId", defaultClientOrderId);
        final Object finalSubaccountId = subaccountId;
        final Object finalOrderFlag = orderFlag;
        final Object finalGoodTillBlock = goodTillBlock;
        final Object finalGoodTillBlockTime = goodTillBlockTime;
        final Object finalTimeInForceNumber = timeInForceNumber;
        final Object finalClientMetadata = clientMetadata;
        final Object finalConditionalType = conditionalType;
        final Object finalConditionalOrderTriggerSubticks = conditionalOrderTriggerSubticks;
        Object orderPayload = new java.util.HashMap<String, Object>() {{
            put( "order", new java.util.HashMap<String, Object>() {{
                put( "orderId", new java.util.HashMap<String, Object>() {{
                    put( "subaccountId", new java.util.HashMap<String, Object>() {{
                        put( "owner", DydxCore.this.getWalletAddress() );
                        put( "number", finalSubaccountId );
                    }} );
                    put( "clientId", clientOrderId );
                    put( "orderFlags", finalOrderFlag );
                    put( "clobPairId", Helpers.GetValue(marketInfo, "clobPairId") );
                }} );
                put( "side", sideNumber );
                put( "quantums", DydxCore.this.toDydxLong(quantums) );
                put( "subticks", DydxCore.this.toDydxLong(subticks) );
                put( "goodTilBlock", finalGoodTillBlock );
                put( "goodTilBlockTime", finalGoodTillBlockTime );
                put( "timeInForce", finalTimeInForceNumber );
                put( "reduceOnly", reduceOnly );
                put( "clientMetadata", finalClientMetadata );
                put( "conditionType", finalConditionalType );
                put( "conditionalOrderTriggerSubticks", DydxCore.this.toDydxLong(finalConditionalOrderTriggerSubticks) );
                put( "orderRouterAddress", DydxCore.this.safeString(DydxCore.this.options, "routerAddress", "dydx165sfn2k3vucvq7gklauy2r3agyjw4c3m60ascn") );
            }} );
        }};
        Object signingPayload = new java.util.HashMap<String, Object>() {{
            put( "typeUrl", "/dydxprotocol.clob.MsgPlaceOrder" );
            put( "value", orderPayload );
        }};
        parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("reduceOnly", "reduce_only", "clientOrderId", "postOnly", "timeInForce", "stopPrice", "triggerPrice", "stopLoss", "takeProfit", "latestBlockHeight", "goodTillBlock", "goodTillBlockTimeInSeconds", "subaccountId")));
        Object orderId = this.createOrderIdFromParts(this.getWalletAddress(), subaccountId, clientOrderId, orderFlag, Helpers.GetValue(marketInfo, "clobPairId"));
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(orderId, this.extend(signingPayload, parameters)));
    }

    public Object createOrderIdFromParts(Object address, Object subAccountNumber, Object clientOrderId, Object orderFlags, Object clobPairId)
    {
        Object nameSp = this.safeString(this.options, "namespace", "0f9da948-a6fb-4c45-9edc-4685c3f3317d");
        Object prefixAddress = Helpers.add(Helpers.add(address, "-"), String.valueOf(subAccountNumber));
        Object prefix = this.uuid5(nameSp, prefixAddress);
        Object orderInfo = Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(prefix, "-"), this.numberToString(clientOrderId)), "-"), this.numberToString(clobPairId)), "-"), this.numberToString(orderFlags));
        return this.uuid5(nameSp, orderInfo);
    }

