    /**
     * @method
     * @name dydx#cancelOrder
     * @description cancels an open order
     * @see https://docs.dydx.xyz/interaction/trading/#cancel-an-order
     * @param {string} id it should be the clientOrderId in this case
     * @param {string} symbol unified symbol of the market the order was made in
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {string} [params.clientOrderId] client order id used when creating the order
     * @param {boolean} [params.trigger] whether the order is a trigger/algo order
     * @param {float} [params.orderFlags] default is 64, orderFlags for the order, market order and non limit GTT order is 0, limit GTT order is 64 and conditional order is 32
     * @param {float} [params.goodTillBlock] expired block number for the order, required for market order and non limit GTT order (orderFlags = 0), default value is latestBlockHeight + 20
     * @param {float} [params.goodTillBlockTimeInSeconds] expired time elapsed for the order, required for limit GTT order and conditional (orderFlagss > 0), default value is 30 days
     * @param {int} [params.subAccountId] sub account id, default is 0
     * @returns {object} An [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> cancelOrder(Object id2, Object... optionalArgs)
    {
        final Object id3 = id2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object id = id3;
            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object isTrigger = this.safeBool2(parameters, "trigger", "stop", false);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("trigger", "stop")));
            if (Helpers.isTrue(!Helpers.isTrue(isTrigger) && Helpers.isTrue((Helpers.isEqual(symbol, null)))))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a symbol argument")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object clientOrderId = this.safeString2(parameters, "clientOrderId", "clientId", id);
            if (Helpers.isTrue(Helpers.isEqual(clientOrderId, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " cancelOrder() requires a clientOrderId parameter, cancelling using id is not currently supported.")) ;
            }
            Object idString = String.valueOf(id);
            if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(id, null)) && Helpers.isTrue(Helpers.isGreaterThan(Helpers.getIndexOf(idString, "-"), Helpers.opNeg(1)))))
            {
                throw new NotSupported((String)Helpers.add(this.id, " cancelOrder() cancelling using id is not currently supported, please use provide the clientOrderId parameter.")) ;
            }
            Object goodTillBlock = this.safeInteger(parameters, "goodTillBlock");
            Object goodTillBlockTimeInSeconds = 2592000;
            var goodTillBlockTimeInSecondsparametersVariable = this.handleOptionAndParams(parameters, "cancelOrder", "goodTillBlockTimeInSeconds", goodTillBlockTimeInSeconds);
            goodTillBlockTimeInSeconds = ((java.util.List<Object>) goodTillBlockTimeInSecondsparametersVariable).get(0);
            parameters = ((java.util.List<Object>) goodTillBlockTimeInSecondsparametersVariable).get(1); // default is 30 days
            Object goodTillBlockTime = null;
            Object defaultOrderFlags = ((Helpers.isTrue((isTrigger)))) ? 32 : 64;
            Object orderFlags = this.safeInteger(parameters, "orderFlags", defaultOrderFlags);
            Object subAccountId = 0;
            var subAccountIdparametersVariable = this.handleOptionAndParams(parameters, "cancelOrder", "subAccountId", subAccountId);
            subAccountId = ((java.util.List<Object>) subAccountIdparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subAccountIdparametersVariable).get(1);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("clientOrderId", "orderFlags", "goodTillBlock", "goodTillBlockTime", "goodTillBlockTimeInSeconds", "subaccountId", "clientId")));
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(orderFlags, 0)) && Helpers.isTrue(!Helpers.isEqual(orderFlags, 64))) && Helpers.isTrue(!Helpers.isEqual(orderFlags, 32))))
            {
                throw new InvalidOrder((String)Helpers.add(this.id, " invalid orderFlags, allowed values are (0, 64, 32).")) ;
            }
            if (Helpers.isTrue(Helpers.isGreaterThan(orderFlags, 0)))
            {
                if (Helpers.isTrue(Helpers.isEqual(goodTillBlockTimeInSeconds, null)))
                {
                    throw new ArgumentsRequired((String)Helpers.add(this.id, " goodTillBlockTimeInSeconds is required in params for long term or conditional order.")) ;
                }
                if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(goodTillBlock, null)) && Helpers.isTrue(Helpers.isGreaterThan(goodTillBlock, 0))))
                {
                    throw new InvalidOrder((String)Helpers.add(this.id, " goodTillBlock should be 0 for long term or conditional order.")) ;
                }
                goodTillBlockTime = Helpers.add(this.seconds(), goodTillBlockTimeInSeconds);
            } else
            {
                if (Helpers.isTrue(Helpers.isEqual(goodTillBlock, null)))
                {
                    Object latestBlockHeight = (this.fetchLatestBlockHeight()).join();
                    goodTillBlock = Helpers.add(latestBlockHeight, 20);
                }
            }
            Object credentials = this.retrieveCredentials();
            Object account = (this.fetchDydxAccount()).join();
            final Object finalSubAccountId = subAccountId;
            final Object finalClientOrderId = clientOrderId;
            final Object finalOrderFlags = orderFlags;
            final Object finalGoodTillBlock = goodTillBlock;
            final Object finalGoodTillBlockTime = goodTillBlockTime;
            Object cancelPayload = new java.util.HashMap<String, Object>() {{
                put( "orderId", new java.util.HashMap<String, Object>() {{
                    put( "subaccountId", new java.util.HashMap<String, Object>() {{
                        put( "owner", DydxCore.this.getWalletAddress() );
                        put( "number", finalSubAccountId );
                    }} );
                    put( "clientId", finalClientOrderId );
                    put( "orderFlags", finalOrderFlags );
                    put( "clobPairId", Helpers.GetValue(Helpers.GetValue(market, "info"), "clobPairId") );
                }} );
                put( "goodTilBlock", finalGoodTillBlock );
                put( "goodTilBlockTime", finalGoodTillBlockTime );
            }};
            Object signingPayload = new java.util.HashMap<String, Object>() {{
                put( "typeUrl", "/dydxprotocol.clob.MsgCancelOrder" );
                put( "value", cancelPayload );
            }};
            Object chainName = Helpers.GetValue(this.options, "chainName");
            Object signedTx = this.signDydxTx(Helpers.GetValue(credentials, "privateKey"), signingPayload, "", chainName, account, null);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "tx", signedTx );
            }};
            // nodeRpcGetBroadcastTxAsync
            Object response = (this.nodeRpcGetBroadcastTxSync(request)).join();
            //
            // {
            //     "jsonrpc": "2.0",
            //     "id": -1,
            //     "result": {
            //         "code": 0,
            //         "data": "",
            //         "log": "[]",
            //         "codespace": "",
            //         "hash": "CBEDB0603E57E5CE21FA6954770A9403D2A81BED02E608C860356152D0AA1A81"
            //     }
            // }
            //
            Object result = this.safeDict(response, "result");
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "info", result );
            }});
        });

    }

