    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        // {
        //     "id": "6a6075bc-7183-5fd9-bc9d-894e238aa527",
        //     "sender": {
        //         "address": "dydx14zzueazeh0hj67cghhf9jypslcf9sh2n5k6art",
        //         "subaccountNumber": 0
        //     },
        //     "recipient": {
        //         "address": "dydx1slanxj8x9ntk9knwa6cvfv2tzlsq5gk3dshml0",
        //         "subaccountNumber": 1
        //     },
        //     "size": "0.000001",
        //     "createdAt": "2025-07-29T09:43:02.105Z",
        //     "createdAtHeight": "45116125",
        //     "symbol": "USDC",
        //     "type": "TRANSFER_OUT",
        //     "transactionHash": "92B4744BA1B783CF37C79A50BEBC47FFD59C8D5197D62A8485D3DCCE9AF220AF"
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object currencyId = this.safeString(item, "symbol");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object type = this.safeStringUpper(item, "type");
        Object direction = null;
        if (Helpers.isTrue(!Helpers.isEqual(type, null)))
        {
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "TRANSFER_IN")) || Helpers.isTrue(Helpers.isEqual(type, "DEPOSIT"))))
            {
                direction = "in";
            } else if (Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(type, "TRANSFER_OUT")) || Helpers.isTrue(Helpers.isEqual(type, "WITHDRAWAL"))))
            {
                direction = "out";
            }
        }
        Object amount = this.safeString(item, "size");
        Object timestamp = this.parse8601(this.safeString(item, "createdAt"));
        Object sender = this.safeDict(item, "sender");
        Object recipient = this.safeDict(item, "recipient");
        final Object finalDirection = direction;
        final Object finalType = type;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", DydxCore.this.safeString(item, "id") );
            put( "direction", finalDirection );
            put( "account", DydxCore.this.safeString(sender, "address") );
            put( "referenceAccount", DydxCore.this.safeString(recipient, "address") );
            put( "referenceId", DydxCore.this.safeString(item, "transactionHash") );
            put( "type", DydxCore.this.parseLedgerEntryType(finalType) );
            put( "currency", code );
            put( "amount", DydxCore.this.parseNumber(amount) );
            put( "timestamp", timestamp );
            put( "datetime", DydxCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", null );
        }}, currency);
    }

