    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        // {
        //     "id": "6a6075bc-7183-5fd9-bc9d-894e238aa527",
        //     "sender": {
        //         "address": "dydx14zzueazeh0hj67cghhf9jypslcf9sh2n5k6art",
        //         "subaccountNumber": 0
        //     },
        //     "recipient": {
        //         "address": "dydx1slanxj8x9ntk9knwa6cvfv2tzlsq5gk3dshml0",
        //         "subaccountNumber": 1
        //     },
        //     "size": "0.000001",
        //     "createdAt": "2025-07-29T09:43:02.105Z",
        //     "createdAtHeight": "45116125",
        //     "symbol": "USDC",
        //     "type": "TRANSFER_OUT",
        //     "transactionHash": "92B4744BA1B783CF37C79A50BEBC47FFD59C8D5197D62A8485D3DCCE9AF220AF"
        // }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object id = this.safeString(transaction, "id");
        Object sender = this.safeDict(transaction, "sender");
        Object recipient = this.safeDict(transaction, "recipient");
        Object addressTo = this.safeString(recipient, "address");
        Object addressFrom = this.safeString(sender, "address");
        Object txid = this.safeString(transaction, "transactionHash");
        Object currencyId = this.safeString(transaction, "symbol");
        Object code = this.safeCurrencyCode(currencyId, currency);
        Object timestamp = this.parse8601(this.safeString(transaction, "createdAt"));
        Object amount = this.safeNumber(transaction, "size");
        return new java.util.HashMap<String, Object>() {{
            put( "info", transaction );
            put( "id", id );
            put( "txid", txid );
            put( "timestamp", timestamp );
            put( "datetime", DydxCore.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", addressTo );
            put( "addressTo", addressTo );
            put( "addressFrom", addressFrom );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "type", DydxCore.this.safeStringLower(transaction, "type") );
            put( "amount", amount );
            put( "currency", code );
            put( "status", null );
            put( "updated", null );
            put( "internal", null );
            put( "comment", null );
            put( "fee", null );
        }};
    }

    /**
     * @method
     * @name dydx#withdraw
     * @description make a withdrawal
     * @param {string} code unified currency code
     * @param {float} amount the amount to withdraw
     * @param {string} address the address to withdraw to
     * @param {string} tag
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [transaction structure]{@link https://docs.ccxt.com/?id=transaction-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> withdraw(Object code2, Object amount, Object address, Object... optionalArgs)
    {
        final Object code3 = code2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object code = code3;
            Object tag = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(code, "USDC")))
            {
                throw new NotSupported((String)Helpers.add(this.id, " withdraw() only support USDC")) ;
            }
            (this.loadMarkets()).join();
            this.checkAddress(address);
            Object subaccountId = this.safeInteger(parameters, "subaccountId");
            if (Helpers.isTrue(Helpers.isEqual(subaccountId, null)))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " withdraw requires subaccountId.")) ;
            }
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("subaccountId")));
            Object currency = this.currency(code);
            Object credentials = this.retrieveCredentials();
            Object account = (this.fetchDydxAccount()).join();
            Object usd = this.parseToInt(Precise.stringMul(this.numberToString(amount), "1000000"));
            final Object finalSubaccountId = subaccountId;
            Object payload = new java.util.HashMap<String, Object>() {{
                put( "sender", new java.util.HashMap<String, Object>() {{
                    put( "owner", DydxCore.this.getWalletAddress() );
                    put( "number", finalSubaccountId );
                }} );
                put( "recipient", address );
                put( "assetId", 0 );
                put( "quantums", usd );
            }};
            Object signingPayload = new java.util.HashMap<String, Object>() {{
                put( "typeUrl", "/dydxprotocol.sending.MsgWithdrawFromSubaccount" );
                put( "value", payload );
            }};
            Object txFee = (this.estimateTxFee(signingPayload, tag, account)).join();
            Object chainName = Helpers.GetValue(this.options, "chainName");
            Object signedTx = this.signDydxTx(Helpers.GetValue(credentials, "privateKey"), signingPayload, tag, chainName, account, null, txFee);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "tx", signedTx );
            }};
            // nodeRpcGetBroadcastTxAsync
            Object response = (this.nodeRpcGetBroadcastTxSync(request)).join();
            //
            // {
            //     "jsonrpc": "2.0",
            //     "id": -1,
            //     "result": {
            //         "code": 0,
            //         "data": "",
            //         "log": "[]",
            //         "codespace": "",
            //         "hash": "CBEDB0603E57E5CE21FA6954770A9403D2A81BED02E608C860356152D0AA1A81"
            //     }
            // }
            //
            Object data = this.safeDict(response, "result", new java.util.HashMap<String, Object>() {{}});
            return this.parseTransaction(data, currency);
        });

    }

